function myReduce(items, func, initialVal) {
  let acc = initialVal !== undefined ? initialVal : items[0];
  let startIdx = initialVal !== undefined ? 0 : 1;
  for (let i = startIdx; i < items.length; i++) {
    acc = func(acc, items[i]);
  }
  return acc;
}

function deepFlatten(arr) {
  return arr.reduce((acc, item) => {
    if (Array.isArray(item)) {
      acc.push(...deepFlatten(item));
    } else {
      acc.push(item);
    }
    return acc;
  }, []);
}

// Binary Search Concept:
// Sorted Array: [1, 3, 5, 7, 9, 11]
// Target: 9 -> Check middle (5), since 9 > 5, search only the right half.

function bubbleSort(arr) {
  let n = arr.length;
  for (let i = 0; i < n; i++) {
    for (let j = 0; j < n - i - 1; j++) {
      if (arr[j] > arr[j + 1]) {
        // Swap elements
        let temp = arr[j];
        arr[j] = arr[j + 1];
        arr[j + 1] = temp;
      }
    }
  }
  return arr;
}

function fibonacci(n, memo = {}) {
  if (n in memo) return memo[n];
  if (n <= 1) return n;
  memo[n] = fibonacci(n - 1, memo) + fibonacci(n - 2, memo);
  return memo[n];
}
